import{bV as s,aL as a,u as i,G as n}from"./chunks/framework.BfzMay2U.js";const k=JSON.parse('{"title":"缓存问题应对方案","description":"","frontmatter":{"title":"缓存问题应对方案","date":"2023-01-07T21:17:10.000Z","categories":["Redis"],"tags":["cache"]},"headers":[],"relativePath":"views/redis/redis-cache-question.md","filePath":"views/redis/redis-cache-question.md"}'),l={name:"views/redis/redis-cache-question.md"};function d(t,e,c,o,p,r){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="缓存问题应对方案" tabindex="-1">缓存问题应对方案 <a class="header-anchor" href="#缓存问题应对方案" aria-label="Permalink to &quot;缓存问题应对方案&quot;">​</a></h1><h2 id="缓存穿透" tabindex="-1">缓存穿透 <a class="header-anchor" href="#缓存穿透" aria-label="Permalink to &quot;缓存穿透&quot;">​</a></h2><blockquote><p>短时间内大量访问不存在的数据，导致穿透<code>redis</code>直接访问数据库，造成数据库瓶颈</p></blockquote><p>一个<code>web</code>程序正常访问流程：</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	A(客户端)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	B(Nginx)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	C(Redis)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	D(MySQL)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	A --&gt; B</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	B -- 去redis找有没有存储的信息 --&gt; C</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	C -- 如果存在 --&gt; B</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	B --&gt; A</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	C -- 如果不存在 --&gt; D</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	D -- 同步一份数据给redis --&gt; C</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	D --&gt; B</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>但是如果你的<code>id</code>是自增模式的，攻击者发来一个小于 0 的数值或者无穷大的数值，这个时候<code>redis</code>就会找不到，会直接到<code>MySQL</code>中查找，间接增加数据库的压力。</p><h3 id="解决办法" tabindex="-1">解决办法 <a class="header-anchor" href="#解决办法" aria-label="Permalink to &quot;解决办法&quot;">​</a></h3><ul><li>没有值时，也保存一个对应的<code>null</code>值在<code>redis</code>中；假如攻击者不断地换 id，就会产生一大堆的没有用的<code>key</code>，内存占满之后，会淘汰掉正常的<code>key</code>，所以也是有问题的</li><li>封禁对方<code>ip</code></li><li>对参数进行校验，把非法的参数给过滤掉</li><li>最终解决办法：布隆过滤器</li></ul><h3 id="布隆过滤器" tabindex="-1">布隆过滤器 <a class="header-anchor" href="#布隆过滤器" aria-label="Permalink to &quot;布隆过滤器&quot;">​</a></h3><p>主旨：采用一个很长的二进制数组，并通过一系列的<code>hash</code>函数来确认该数据是否存在。</p><p>哈希函数要满足两点</p><ol><li>范围必须是数组的长度</li><li>足够的散列</li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p>数组中只有 0 和 1，它说数据不存在，那么数据是一定不存在的；它说数据存在，数据是有可能不存在的。</p><p>如何减少误判产生：</p><ol><li>增加数组的位置，当数组越长的时候，哈希的值就会越散列，越分散，重复可能性就会越小</li><li>增加哈希的次数，就会增加 CPU 的运算，效率会降低</li><li>不能只保存 0 和 1，还要存储计数信息</li></ol><p>优点：</p><p>二进制组成的数组，占用内存极少，并且插入和查询速度都足够快</p><p>缺点：</p><p>随着数据的增加，误判率会增加；还有无法判断数据一定存在；无法删除数据</p></div><h2 id="缓存雪崩" tabindex="-1">缓存雪崩 <a class="header-anchor" href="#缓存雪崩" aria-label="Permalink to &quot;缓存雪崩&quot;">​</a></h2><blockquote><p>大量<code>redis key</code>同一时间失效，导致请求访问到数据库，造成数据库瓶颈</p></blockquote><p>案例：网站首页在某一时刻有大量访问，这个时候会存储一定数据一定时间在<code>redis</code>中，在这个时效之内，访问都可以直接通过<code>redis</code>得到信息，但是如果失效了，这些<code>key</code>集体失效了，这个时候再次访问，就会集体访问<code>MySQL</code>，很可能就会遇到瓶颈。</p><h3 id="解决办法-1" tabindex="-1">解决办法 <a class="header-anchor" href="#解决办法-1" aria-label="Permalink to &quot;解决办法&quot;">​</a></h3><ul><li>过期时间随机设置</li><li>定时任务重新设置过期时间，在过期前重新设置，保证缓存不失效</li><li>永不过期(不推荐)</li></ul><h2 id="缓存击穿" tabindex="-1">缓存击穿 <a class="header-anchor" href="#缓存击穿" aria-label="Permalink to &quot;缓存击穿&quot;">​</a></h2><blockquote><p>一个热点的<code>key</code>失效，导致访问这个热点<code>key</code>的请求，直接访问数据库，造成数据库瓶颈</p></blockquote><p>案例：竞拍一些商品时，会预估一下过期时间，但是也会有延后的情况，而在这延后的时候，它过期了，就会导致所有请求一下子访问<code>MySQL</code>，即热点<code>key</code>突然失效问题。</p><h3 id="解决办法-2" tabindex="-1">解决办法 <a class="header-anchor" href="#解决办法-2" aria-label="Permalink to &quot;解决办法&quot;">​</a></h3><ul><li>加锁，分布式锁或互斥锁</li></ul><p>当第一个请求在<code>redis</code>中没有找到<code>key</code>时，访问<code>MySQL</code>时，这个时候先上锁，其他没有拿到锁的请求继续等待，第一个请求拿到数据之后就会把数据同步到<code>redis</code>，其他请求等待以后在请求以后<code>redis</code>就有数据了。</p>`,24)])])}const u=s(l,[["render",d]]);export{k as __pageData,u as default};
